public static long[] solve(String[] words) {
    int n = words.length;
    long[] answer = new long[n];

    if (n == 1) {
        return answer; // all 0 since no adjacent pairs
    }

    // Precompute the LCP for adjacent pairs in the original array
    int[] originalLCP = new int[n - 1];
    for (int i = 0; i < n - 1; i++) {
        originalLCP[i] = computeLCP(words[i], words[i + 1]);
    }

    // For each i, compute the answer after removing words[i]
    for (int i = 0; i < n; i++) {
        int maxLCP = 0;

        if (n == 2) {
            // Only one pair, removing any element leaves no pairs
            answer[i] = 0;
            continue;
        }

        // The LCPs that are affected are originalLCP[i-1] and originalLCP[i] (if they exist)
        // The new LCPs after removal are:
        // - originalLCP[j] where j < i-1
        // - new LCP between words[i-1] and words[i+1] (if i-1 and i+1 are valid)
        // - originalLCP[j] where j > i

        // Iterate through all possible adjacent pairs after removal
        for (int j = 0; j < n - 1; j++) {
            if (j == i - 1) {
                // This pair is words[j] and words[j+1], but words[i] is removed (j+1 == i)
                // So the new pair is words[j] and words[j+2] (if j+2 exists)
                if (j + 2 < n) {
                    int newLCP = computeLCP(words[j], words[j + 2]);
                    if (newLCP > maxLCP) {
                        maxLCP = newLCP;
                    }
                }
            } else if (j == i) {
                // This pair is words[j] and words[j+1], but words[i] is removed
                // So this pair is skipped
                continue;
            } else {
                // This pair is not affected by the removal
                if (originalLCP[j] > maxLCP) {
                    maxLCP = originalLCP[j];
                }
            }
        }

        answer[i] = maxLCP;
    }

    return answer;
}

private static int computeLCP(String a, String b) {
    int minLen = Math.min(a.length(), b.length());
    int lcp = 0;
    while (lcp < minLen && a.charAt(lcp) == b.charAt(lcp)) {
        lcp++;
    }
    return lcp;
